command:
mkdir -p tree/g && printf '
recommended_set: ["rule-a"]
rules:
  - {id: rule-a, provenance: [{source: g, section_id: "1.1"}]}
  - {id: rule-b, provenance: [{source: g, section_id: "1.2"}]}
' > tree/g/x.yaml && bash "$CLAUDE_PLUGIN_ROOT/standards/build-coverage-matrix.sh" --tree tree --emit m.json 2>err.txt && node -e 'const j=JSON.parse(require("fs").readFileSync("m.json","utf8"));process.exit(j.sources.g.recommended_count===1?0:1)' && echo recommended 1>&2
